package.sql:
      
        DECLARE
        BEGIN
            SP_MAPPER.PUT_MWL(
                    @EVENT_TYPE, -- event_type
                    @ORDER_CONTROL_ID, -- order_control_id
                    @CHARACTER_SET, -- character_set
                    @SCHEDULED_AETITLE, -- scheduled_aetitle
                    @SCHEDULED_DTTM, -- scheduled_dttm
                    @SCHEDULED_MODALITY, -- scheduled_modality
                    @SCHEDULED_STATION, -- scheduled_station
                    @SCHEDULED_LOCATION, -- scheduled_location
                    @SCHEDULED_PROC_ID, -- scheduled_proc_id
                    @SCHEDULED_PROC_DESC, -- scheduled_proc_desc
                    @SCHEDULED_ACTION_CODES, -- scheduled_action_codes
                    @SCHEDULED_PROC_STATUS, -- scheduled_proc_status
                    @PREMEDICATION, -- premedication
                    @CONTRAST_AGENT, -- contrast_agent
                    @REQUESTED_PROC_ID, -- requested_proc_id
                    @REQUESTED_PROC_DESC, -- requested_proc_desc
                    @REQUESTED_PROC_CODES, -- requested_proc_codes
                    @REQUESTED_PROC_PRIORITY, -- requested_proc_priority
                    @REQUESTED_PROC_REASON, -- requested_proc_reason
                    @REQUESTED_PROC_COMMENTS, -- requested_proc_comments
                    @STUDY_INSTANCE_UID, -- study_instance_uid
                    @PROC_PLACER_ORDER_NO, -- proc_placer_order_no
                    @PROC_FILLER_ORDER_NO, -- proc_filler_order_no
                    @ACCESSION_NO, -- accession_no
                    @ATTEND_DOCTOR, -- attend_doctor
                    @PERFORM_DOCTOR, -- perform_doctor
                    @CONSULT_DOCTOR, -- consult_doctor
                    @REQUEST_DOCTOR, -- request_doctor
                    @REFER_DOCTOR, -- refer_doctor
                    @REQUEST_DEPARTMENT, -- request_department
                    @IMAGING_REQUEST_REASON, -- imaging_request_reason
                    @IMAGING_REQUEST_COMMENTS, -- imaging_request_comments
                    @IMAGING_REQUEST_DTTM, -- imaging_request_dttm
                    @ISR_PLACER_ORDER_NO, -- isr_placer_order_no
                    @ISR_FILLER_ORDER_NO, -- isr_filler_order_no
                    @ADMISSION_ID, -- admission_id
                    @PATIENT_TRANSPORT, -- patient_transport
                    @PATIENT_LOCATION, -- patient_location
                    @PATIENT_RESIDENCY, -- patient_residency
                    @PATIENT_NAME, -- patient_name
                    @PATIENT_ID, -- patient_id
                    @OTHER_PATIENT_NAME, -- other_patient_name
                    @OTHER_PATIENT_ID, -- other_patient_id
                    @PATIENT_BIRTH_DATE, -- patient_birth_date
                    @PATIENT_SEX, -- patient_sex
                    @PATIENT_WEIGHT, -- patient_weight
                    @PATIENT_SIZE, -- patient_size
                    @PATIENT_STATE, -- patient_state
                    @CONFIDENTIALITY, -- confidentiality
                    @PREGNANCY_STATUS, -- pregnancy_status
                    @MEDICAL_ALERTS, -- medical_alerts
                    @CONTRAST_ALLERGIES, -- contrast_allergies
                    @SPECIAL_NEEDS, -- special_needs
                    @SPECIALTY, -- specialty
                    @DIAGNOSIS, -- diagnosis
                    @ADMIT_DTTM, -- admit_dttm
                    @REGISTER_DTTM, -- register_dttm
                    @STUDY_SSN -- study_ssn
                );
        END;

      
        DECLARE
          v_study_key NUMBER;
          v_insurancefee_key NUMBER;
          v_order_control_id  VARCHAR2(32) := @ORDER_CONTROL_ID;
          v_scheduled_procedure_step VARCHAR2(32) := @SCHEDULED_PROC_STATUS;
		  v_msps_key NUMBER;
        BEGIN
          v_study_key := SP_MAPPER.put_order(
                            @EVENT_TYPE, -- event_type
                            @ORDER_CONTROL_ID, -- order_control_id
                            @PATIENT_ID, -- patient_id
                            null, -- patient_id_issuer_code
                            @PATIENT_NAME, -- patient_name
                            null, -- last_name
                            null, -- first_name
                            null, -- middle_name
                            null, -- prefix
                            null, -- suffix
                            @PATIENT_BIRTH_DATE, -- patient_birth_dttm
                            @PATIENT_SEX, -- patient_sex
                            null, -- race_code
                            @CONFIDENTIALITY, -- confidentiality
                            null, -- account_no
                            null, -- address
                            @PATIENT_LOCATION, -- patient_location
                            @PATIENT_RESIDENCY, -- patient_residence
                            @REFER_DOCTOR, -- refer_doctor_id
                            @CONSULT_DOCTOR, -- consult_doctor_id
                            @PROC_PLACER_ORDER_NO, -- placer_order_id
                            @PROC_FILLER_ORDER_NO, -- filler_order_id
                            @ACCESSION_NO, -- accession_no
                            @SCHEDULED_PROC_STATUS, -- order_stat
                            @IMAGING_REQUEST_REASON, -- order_reason
                            @IMAGING_REQUEST_COMMENTS, -- order_comments
                            @IMAGING_REQUEST_DTTM, -- order_dttm
                            @REQUEST_DOCTOR, -- order_doctor_id
                            @REQUEST_DEPARTMENT, -- order_department
                            null, -- order_entry_user_id
                            null, -- order_entry_location
                            null, -- order_callback_phone_no
                            @ATTEND_DOCTOR, -- attend_doctor_id
                            @PERFORM_DOCTOR, -- perform_doctor_id
                            null, -- reqproc_stat
                            @REQUESTED_PROC_ID, -- reqproc_id
                            @REQUESTED_PROC_DESC, -- reqproc_desc
                            @REQUESTED_PROC_CODES, -- reqproc_code_value
                            null, -- reqproc_code_scheme
                            null, -- reqproc_code_version
                            null, -- reqproc_code_meaning
                            @STUDY_INSTANCE_UID, -- study_instance_uid
                            @REQUESTED_PROC_REASON, -- reqproc_reason
                            @REQUESTED_PROC_COMMENTS, -- reqproc_comments
                            @REQUESTED_PROC_PRIORITY, -- reqproc_priority
                            null, -- reqproc_location
                            null, -- patient_arrange
                            @DIAGNOSIS, -- diagnosis for ODBC
                            @OTHER_PATIENT_ID, -- other_patient_id for ODBC
                            @OTHER_PATIENT_NAME, -- other_patient_name for ODBC
                            'AE', -- source_aetitle
                            'BROKER', -- broker_aetitle
                            'ODBC' -- broker_type
                          );
          
          IF v_order_control_id = 'NW' AND v_scheduled_procedure_step IN ('120', '110', 'SC') THEN
            v_msps_key := SP_MAPPER.put_msps(
                            v_study_key, -- study_key
                            @REQUESTED_PROC_CODES, -- reqproc_code_value
                            null, -- reqproc_code_scheme
                            @SCHEDULED_PROC_ID, -- sps_id
                            @SCHEDULED_MODALITY, -- modality
                            @SCHEDULED_DTTM, -- sps_start_dttm
                            @SCHEDULED_PROC_ID, -- protcode_value
                            @SCHEDULED_ACTION_CODES, -- protcode_scheme
                            @SCHEDULED_PROC_DESC, -- protcode_meaning
                            1, -- index
                            'AE', -- aetitle
                            @SCHEDULED_LOCATION, -- scheduled_location
                            'ODBC', -- broker_type : 'HL7-PACS' = PACS Only, 'HL7-IHE' = RIS & PACS
                            @ORDER_CONTROL_ID, -- order_control_id
                            @SCHEDULED_PROC_STATUS -- order_stat
                          );
          END IF;
          
          /*
          v_insurancefee_key := SP_MAPPER.put_insurancefee(
                                  @STUDY_INSTANCE_UID, -- study_instance_uid
                                  @PATIENT_ID, -- patient_id
                                  @PATIENT_BIRTH_DATE, -- patient_birth_dttm
                                  @SCHEDULED_DTTM, -- request_dttm
                                  @REQUESTED_PROC_ID, -- request_code
                                  @REQUESTED_PROC_DESC, -- request_name
                                  @ACCESSION_NO, -- accession_no
                                  @INSURANCE_CODE, -- insurance_code
                                  @SCHEDULED_MODALITY, -- modality
                                  @EMERGENCY, -- emergency
                                  @SPECIAL_DOCTOR, -- special_doctor
                                );
            */                     
        END;


  DECLARE
    v_patient_key NUMBER;
  BEGIN
    v_patient_key := SP_MAPPER.put_patient(
                      @EVENT_TYPE, -- event_type
                      @PATIENT_ID, -- patient_id
                      null, -- prior_patient_id
                      null, -- patient_id_issuer_code
                      @PATIENT_SSN, -- patient_ssn
                      @PATIENT_NAME, -- patient_name
                      null, -- last_name
                      null, -- first_name
                      null, -- middle_name
                      null, -- prefix
                      null, -- suffix
                      null, -- marital_stat
                      null, -- confidentiality
                      @PATIENT_BIRTH_DTTM, -- patient_birth_dttm
                      null, -- patient_death_dttm
                      @PATIENT_SEX, -- patient_sex
                      @PATIENT_SIZE, -- patient_size
                      @PATIENT_WEIGHT, -- patient_weight
                      @BLOOD_TYPE, -- blood_type_abo
                      null, -- blood_type_rh
                      null, -- citizenship
                      null, -- occupation
                      null, -- race_code
                      null, -- language_code
                      null, -- religion_code
                      null, -- birthplace
                      null, -- multiple_birth_status
                      null, -- birth_order
                      @EMAIL, -- email
                      null, -- phone_no
                      null, -- pregnancy_code
                      null, -- patient_stat
                      null, -- account_no
                      null, -- contact_type
                      @TEL_NO, -- home_phone_no
                      null, -- busi_phone_no
                      @FAX_NO, -- fax_no
                      @ADDRESS, -- address
                      null, -- city
                      null, -- state
                      null, -- country
                      @ZIPCODE, -- zipcode
                      null, -- visit_number
                      null, -- visit_stat
                      @ADMIT_DTTM, -- admit_dttm
                      @DISCHARGE_DTTM, -- discharge_dttm
                      @CURRENT_LOCATION, -- patient_location
                      @CURRENT_RESIDENCY, -- patient_residence
                      @CURRENT_DOCTOR_ID, -- refer_doctor_id
                      null, -- consult_doctor_id
                      null, -- institution_code
                      null, -- visit_comment
                      null, -- admit_route
                      null, -- lastmen_strual_dttm
                      @PREGNANCY_STATUS, -- pregnancy_status
                      null, -- code_abbreviation
                      null, -- station_code
                      @ENGLISH_NAME, -- english_name
                      @ETHNIC_GROUP, -- ethnic_group
                      @CURRENT_DEPARTMENT, -- current_department
                      @CURRENT_DOCTOR_NAME, -- refer_doctor_name
                      null, -- consult_doctor_name
                      'BROKER', -- broker_aetitle
                      'ODBC' -- broker_type
                      );
  END;


  DECLARE
    v_report_key NUMBER;
  BEGIN
    v_report_key := SP_MAPPER.put_report(
                        null, -- event_type
                        null, -- report_control_id
                        @EXAM_ID, -- accession_no
                        @PATIENT_ID, -- patient_id
                        @REPORT_STAT, -- report_stat
                        @CREATOR_ID, -- creator_id
                        @CREATOR_NAME, -- creator_name
                        @CREATE_DTTM, -- create_dttm
                        @DICTATOR_ID, -- dictator_id
                        @DICTATOR_NAME, -- dictator_name
                        @DICTATE_DTTM, -- dictate_dttm
                        @TRANSCRIBER_ID, -- transcriber_id
                        @TRANSCRIBER_NAME, -- transcriber_name
                        @TRANSCRIBE_DTTM, -- transcribe_dttm
                        @APPROVER_ID, -- approver_id
                        @APPROVER_NAME, -- approver_name
                        @APPROVE_DTTM, -- approve_dttm
                        @REVISER_ID, -- reviser_id
                        @REVISER_NAME, -- reviser_name
                        @REVISE_DTTM, -- revise_dttm
                        @REPORT_TYPE, -- report_type
                        $REPORT_TEXT, -- report_text  -- limit size : 32768
                        @CONCLUSION, -- conclusion
                        'ODBC' -- broker_type
                      );
  END;


  DECLARE
    v_user_key NUMBER;
  BEGIN
    v_user_key := SP_MAPPER.put_user(
                    @USER_ID, -- user_id
                    @USER_NAME, -- user_name
                    @PASSWORD, -- password
                    @USER_LEVEL, -- user_level
                    @USER_STATUS, -- user_status
                    @COMMENTS -- comments
                  );
  END;


  BEGIN
    DELETE FROM study_ris where accession_no = @ACCESS_NO;
    INSERT INTO study_ris(INPUT_DATE, STUDY_KEY, PATIENT_ID, ACCESSION_NO, STUDY_STAT, STUDY_INSTANCE_UID, STUDY_DTTM, REQUEST_CODE, REQUEST_NAME, PERFORM_MODALITY, PERFORM_STATION, SOURCE_AETITLE, SCHEDULED_LOCATION, PERFORM_DEPARTMENT, SCHEDULED_DTTM, PATIENT_LOCATION, REQUEST_DTTM, ADMISSION_ID, REQUEST_DOCTOR) 
      VALUES (TOCHAR(SYSDATE, 'yyyymmddhh24miss'), @STUDY_KEY, @PATIENT_ID, @ACCESS_NO, @STUDY_STAT, @STUDY_INSTANCE_UID, @STUDY_DTTM, @REQUEST_CODE, @REQUEST_NAME, @MODALITIES, @STATION_NAME, @SOURCE_AETITLE, @SPS_LOCATION, @DEPARTMENT, @SPS_START_DTTM, @PATIENT_LOCATION, @REQUEST_DTTM, null, null);
  END;

      
        DECLARE
            v_report_type varchar2(10) := @OBJECT_TYPE;
            v_report_stat varchar2(10);
        BEGIN
            DELETE FROM report_ris WHERE accession_no = @ACCESS_NO;

            IF v_report_type = 'R' THEN
                v_report_stat := @STUDY_STAT;
            ELSE
                v_report_stat := @ADDENDUM_STAT;
            END IF;
            
            v_report_stat := NVL(v_report_stat, 'F');
    
            INSERT INTO report_ris (patient_id, accession_no, study_instance_uid, report_stat, creator_id, creator_name, create_dttm, dictator_id, dictator_name, dictate_dttm, transcriber_id, transcriber_name, transcribe_dttm, approver_id, approver_name, approve_dttm, reviser_id, reviser_name, revise_dttm, report_type, report_text, conclusion, study_dttm, scheduled_location, perform_department, perform_modality, request_dttm, request_name, request_code, request_doctor, perform_doctor, refer_doctor, scheduled_dttm, patient_name, patient_sex, patient_birth_dttm, admission_id, study_comments, study_reason, attend_doctor)
                VALUES (@PATIENT_ID, @ACCESS_NO, @STUDY_INSTANCE_UID, v_report_stat, @CREATE_USERID, @CREATE_USERNAME, @CREATE_DTTM, @DICTATE_USERID, @DICTATE_USERNAME, @DICTATE_DTTM, @TRANSCRIBE_USERID, @TRANCRIBE_USERNAME, @TRANSCRIBE_DTTM, @APPROVE_USERID, @APPROVE_USERNAME, @APPROVE_DTTM, @REVISE_USERID, @REVISE_USERNAME, @REVISE_DTTM, @REPORT_TYPE, @REPORT_TEXT, @CONCLUSION, @STUDY_DTTM, @INSTITUTION, @DEPARTMENT, @MODALITIES, @REQUEST_DTTM, @REQUEST_NAME, @REQUEST_CODE, @REQUEST_DOCTOR, @PERFORM_DOCTOR, @REFER_DOCTOR, @SPS_START_DTTM, @PATIENT_NAME, @PATIENT_SEX, @PATIENT_BIRTH_DTTM, @SPS_ID, @STUDY_COMMENTS, @STUDY_REASON, @OPERATORS);
        END;
